import shioaji as _sj

_EXPORTS = {
    "Deal": "Deal",
    "OrderStatus": "OrderStatus",
    "StockOrder": "StockOrder",
    "FuturesOrder": "FuturesOrder",
    "Order": "Order",
    "Trade": "Trade",
    "ComboTrade": "ComboTrade",
    "OrderResult": "OrderResult",
    "OrderStatusInfo": "OrderStatusInfo",
    "ComboStatus": "ComboStatus",
}

def __getattr__(name):
    if name in _EXPORTS:
        import warnings
        warnings.warn(
            f"shioaji.order.{name} is deprecated, use sj.{_EXPORTS[name]}",
            DeprecationWarning,
            stacklevel=2,
        )
        return getattr(_sj, _EXPORTS[name])
    raise AttributeError(f"module 'shioaji.order' has no attribute {name!r}")
